    schedMap[e.dow].push({ start: e.start_hour, end: e.end_hour });
  }
  var nowUTC   = new Date();
  var nowLimaMs = nowUTC.getTime() - OFFSET_HOURS * 3600000;
  var nowLima  = new Date(nowLimaMs);
  var slots = [];
  var dname = doctor.display_name || ("Dr. " + doctor.first_name + " " + doctor.last_name);

  for (var day = 0; day < 14; day++) {
    var limaDay = new Date(nowLima);
    limaDay.setDate(limaDay.getDate() + day);
    limaDay.setHours(0, 0, 0, 0);
    var dow = limaDay.getDay();
    var windows = schedMap[dow];
    if (!windows || windows.length === 0) continue;

    for (var wi = 0; wi < windows.length; wi++) {
      var win = windows[wi];
      for (var hour = win.start; hour < win.end; hour++) {
        for (var min = 0; min < 60; min += duration) {
          var slotLimaMs  = limaDay.getTime() + (hour * 60 + min) * 60000;
          var slotStartUTC = new Date(slotLimaMs + OFFSET_HOURS * 3600000);
          var slotEndUTC   = new Date(slotStartUTC.getTime() + duration * 60000);
          if (slotStartUTC <= nowUTC) continue;
          var avail = true;
          for (var ti = 0; ti < busyTimes.length; ti++) {
            if (slotStartUTC < busyTimes[ti].end && slotEndUTC > busyTimes[ti].start) { avail = false; break; }
          }
          if (avail) {
            var displayDate = new Date(slotLimaMs);
            slots.push({
              start: slotStartUTC.toISOString(),
              end:   slotEndUTC.toISOString(),
              date:  displayDate.toLocaleDateString("es-PE", { weekday: "long", year: "numeric", month: "long", day: "numeric" }),
              time:  displayDate.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit" }),
              doctor_id:   doctor.id,
              doctor_name: dname,
              specialty:   doctor.specialty || ""
            });
          }
        }
      }
    }
  }
  return slots;
}

// Helper: legacy mode using bot_config business hours
function buildLegacySlots(busyTimes, botConfig) {
  var bStart = (botConfig && botConfig.business_hours_start) ? botConfig.business_hours_start : 9;
  var bEnd   = (botConfig && botConfig.business_hours_end)   ? botConfig.business_hours_end   : 19;
  var business_hours = { 1: { start: bStart, end: bEnd }, 2: { start: bStart, end: bEnd },
    3: { start: bStart, end: bEnd }, 4: { start: bStart, end: bEnd },
    5: { start: bStart, end: bEnd }, 6: { start: 9, end: 14 }, 0: null };
  var duration = 30;
  var nowUTC   = new Date();
  var nowLimaMs = nowUTC.getTime() - OFFSET_HOURS * 3600000;
  var nowLima  = new Date(nowLimaMs);
  var slots = [];
  for (var day = 0; day < 14; day++) {
    var limaDay = new Date(nowLima);
    limaDay.setDate(limaDay.getDate() + day);
    limaDay.setHours(0, 0, 0, 0);
    var hours = business_hours[limaDay.getDay()];
    if (!hours) continue;
    for (var hour = hours.start; hour < hours.end; hour++) {
      for (var min = 0; min < 60; min += duration) {
        var slotLimaMs  = limaDay.getTime() + (hour * 60 + min) * 60000;
        var slotStartUTC = new Date(slotLimaMs + OFFSET_HOURS * 3600000);
        var slotEndUTC   = new Date(slotStartUTC.getTime() + duration * 60000);
        if (slotStartUTC <= nowUTC) continue;
        var avail = true;
        for (var ti = 0; ti < busyTimes.length; ti++) {
          if (slotStartUTC < busyTimes[ti].end && slotEndUTC > busyTimes[ti].start) { avail = false; break; }
        }
        if (avail) {
          var displayDate = new Date(slotLimaMs);
          slots.push({
            start: slotStartUTC.toISOString(), end: slotEndUTC.toISOString(),
            date:  displayDate.toLocaleDateString("es-PE", { weekday: "long", year: "numeric", month: "long", day: "numeric" }),
            time:  displayDate.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit" }),
            doctor_id: null, doctor_name: null, specialty: null
          });
        }
      }
    }
  }
  return slots;
}

// ── Main logic ──────────────────────────────────────────────────────────
var available_slots = [];

if (mode === "legacy" || available_doctors.length === 0) {
  // No doctors configured — use clinic business hours
  available_slots = buildLegacySlots(busyGeneral, ctx.bot_config).slice(0, 20);

} else if (mode === "specific" && selected_doctor) {
  // Specific doctor requested
  var busy = busyByDoctor[selected_doctor.id] || [];
  available_slots = buildDoctorSlots(selected_doctor, busy).slice(0, 20);

} else {
  // "any" mode — compute slots for all doctors, sort chronologically
  for (var di = 0; di < available_doctors.length; di++) {
    var doc = available_doctors[di];
    var dBusy = busyByDoctor[doc.id] || [];
    var dSlots = buildDoctorSlots(doc, dBusy);
    for (var si = 0; si < dSlots.length; si++) available_slots.push(dSlots[si]);
  }
  available_slots.sort(function(a, b) { return new Date(a.start) - new Date(b.start); });
  available_slots = available_slots.slice(0, 20);
}

return [{
  json: Object.assign({}, ctx, {
    available_slots: available_slots,
    total_available: available_slots.length,
    busy_events_count: busy_events.length,
    calculated_at: new Date().toISOString()
  })
}];

// SELECCIONAR 3 MEJORES SLOTS — prioriza preferencias del paciente y doctor
const all_slots = $json.available_slots || [];
const preferred_dow  = $json.preferred_dow;
const pref_h_start   = $json.preferred_hour_start;
const pref_h_end     = $json.preferred_hour_end;

if (all_slots.length === 0) {
  return [{ json: Object.assign({}, $json, {
    selected_slots: [], no_slots_available: true, should_escalate: true,
    escalation_reason: "NO_SLOTS_AVAILABLE",
    escalation_message: "No encontramos horarios en los proximos 14 dias. Te conecto con un asesor."
  }) }];
}

var scored = all_slots.map(function(slot) {
  var dt       = new Date(slot.start);
  var limaDate = new Date(dt.getTime() - 5 * 3600000);
  var limaHour = limaDate.getUTCHours();
  var limaDow  = limaDate.getUTCDay();
  var score    = 0;
  var dayMatch  = (preferred_dow    != null && limaDow  === preferred_dow);
  var hourMatch = (pref_h_start     != null && limaHour >= pref_h_start && limaHour < pref_h_end);
  if (dayMatch && hourMatch) score = 200;
  else if (dayMatch)         score = 100;
  else if (hourMatch)        score = 50;
  return Object.assign({}, slot, { _score: score, _dow: limaDow, _hour: limaHour });
});

scored.sort(function(a, b) {
  if (b._score !== a._score) return b._score - a._score;
  return new Date(a.start) - new Date(b.start);
});

var selected = scored.slice(0, 3);

var slot_options = selected.map(function(slot, idx) {
  return {
    option_number: idx + 1,
    date:         slot.date,
    time:         slot.time,
    start_iso:    slot.start,
    end_iso:      slot.end,
    doctor_id:    slot.doctor_id   || null,
    doctor_name:  slot.doctor_name || null,
    specialty:    slot.specialty   || null
  };
});

var best_score = scored[0] ? scored[0]._score : 0;
var pref_note  = "";
if (preferred_dow !== null && preferred_dow !== undefined && best_score < 100) {
  var dow_names = ["domingo","lunes","martes","miercoles","jueves","viernes","sabado"];
  pref_note = "El " + (dow_names[preferred_dow] || "") + " no hay disponibilidad en los proximos 14 dias.";
} else if (preferred_dow !== null && preferred_dow !== undefined && pref_h_start !== null && pref_h_start !== undefined && best_score < 200) {
  pref_note = "No hay ese horario exacto disponible.";
}

return [{ json: Object.assign({}, $json, {
  selected_slots: slot_options,
  has_slots: true,
  total_offered: slot_options.length,
  preference_note: pref_note
}) }];

// FORMAT SLOT OFFER MESSAGE
const slots    = $json.selected_slots || [];
const prefNote = $json.preference_note || "";

if (slots.length === 0) {
  return [{ json: Object.assign({}, $json, {
    offer_message: "No encontramos horarios disponibles en los proximos 14 dias. Te conecto con un asesor para ayudarte a coordinar.",
    should_escalate: true, escalation_reason: "NO_SLOTS_AVAILABLE",
    escalation_message: "Sin disponibilidad en 14 dias. Paciente necesita ayuda para agendar."
  }) }];
}

var nl = String.fromCharCode(10);
var message = "\ud83d\udcc5 *Horarios disponibles:*" + nl + nl;

if (prefNote) {
  message = "\ud83d\udcc5 " + prefNote + nl + nl + "Te muestro los mas proximos:" + nl + nl;
}

for (var i = 0; i < slots.length; i++) {
  var s = slots[i];
  var line = "*" + s.option_number + ".* " + s.date + " a las *" + s.time + "*";
  if (s.doctor_name) { line += " — " + s.doctor_name; }
  message += line + nl;
}

message += nl + "Responde con *1*, *2* o *3* para confirmar \ud83d\ude0a" + nl + "O dime si prefieres otro dia de la semana.";

return [{ json: Object.assign({}, $json, {
  offer_message: message,
  offered_slots: slots,
  awaiting_slot_confirmation: true,
  should_escalate: false
}) }];

// MARCAR ESPERANDO CONFIRMACION
const ctx = $node["Formatear Oferta de Slots"].json;
const account_id = ctx.account_id;
const conversation_id = ctx.conversation_id;
const token = $node["Merge Clinic Data"].json.chatwoot_api_token;
const baseUrl = 'https://chat.redsolucionesti.com/api/v1/accounts/' + account_id;
const headers = { 'api_access_token': token, 'Content-Type': 'application/json' };

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/conversations/' + conversation_id + '/labels',
    headers: headers,
    body: { labels: ['awaiting_slot'] }
  });
} catch(e) {
  console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'LABEL_ERROR', error: e.message }));
}

const slots = ctx.selected_slots || [];
if (slots.length > 0) {
  try {
    const notePayload = {
      slots: slots,
      original_message: ctx.message_text || '',
      clinic_name: ctx.clinic_name || '',
      clinic_phone: (ctx.bot_config && ctx.bot_config.phone) ? ctx.bot_config.phone : ''
    };
    await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/conversations/' + conversation_id + '/messages',
      headers: headers,
      body: { content: 'SOFIA_SLOTS:' + JSON.stringify(notePayload), message_type: 'outgoing', private: true }
    });
    console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_STORED', count: slots.length }));
  } catch(e) {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_STORE_ERROR', error: e.message }));
  }
}

return [{
  json: {
    message_text: ctx.message_text, conversation_id: ctx.conversation_id,
    inbox_id: ctx.inbox_id, clinic_id: ctx.clinic_id,
    clinic_name: ctx.clinic_name, bot_config: ctx.bot_config,
    contact_phone: ctx.contact_phone, contact_id: ctx.contact_id,
    account_id: ctx.account_id, message_type: ctx.message_type,
    message_timestamp: ctx.message_timestamp,
    bot_interaction_count: ctx.bot_interaction_count,
    sender_name: ctx.sender_name, sender_email: ctx.sender_email,
    conversation_status: ctx.conversation_status,
    has_contact_inbox: ctx.has_contact_inbox, channel_type: ctx.channel_type,
    intent: ctx.intent, confidence: ctx.confidence,
    selected_slots: ctx.selected_slots || [],
    label_set: true, slots_stored: slots.length > 0
  }
}];

// ============================================
// PREPARE ESCALATION WITH SLOT CONTEXT
// ============================================
const slots = $json.offered_slots || [];

let escalation_note = 'Paciente solicitó agendar cita.\n\n';
escalation_note += 'Horarios ofrecidos:\n';

slots.forEach(slot => {
  escalation_note += `${slot.option_number}. ${slot.date} a las ${slot.time}\n`;
});

escalation_note += '\nEsperando respuesta del paciente para confirmar el horario.';

return [{
  json: {
    ...$json,
    escalation_message: 'Gracias. Un agente se pondrá en contacto contigo pronto para confirmar tu cita.',
    escalation_note: escalation_note,
    escalation_reason: 'PHASE3_SLOTS_OFFERED',
    should_escalate: true
  }
}];

// CHECK IF AWAITING SLOT CONFIRMATION
const validar_data = $node["Validar Input"].json;
const convLabels = (validar_data.raw_payload && validar_data.raw_payload.conversation && validar_data.raw_payload.conversation.labels) ? validar_data.raw_payload.conversation.labels : [];
const awaitingViaLabel = convLabels.includes("awaiting_slot");
const custom_attrs = (validar_data.raw_payload && validar_data.raw_payload.conversation) ? validar_data.raw_payload.conversation.custom_attributes : {};
const awaitingViaAttr = custom_attrs && custom_attrs.awaiting_slot_confirmation === "true";
const awaiting = awaitingViaLabel || awaitingViaAttr;

console.log(JSON.stringify({ ts: new Date().toISOString(), awaiting_label: awaitingViaLabel, labels: convLabels }));

let slots = [];
let original_message = '';
let slot_clinic_name = '';
let slot_clinic_phone = '';

if (awaiting) {
  try {
    const account_id = validar_data.account_id;
    const conversation_id = validar_data.conversation_id;
    const token = $node["Merge Clinic Data"].json.chatwoot_api_token;
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://chat.redsolucionesti.com/api/v1/accounts/' + account_id + '/conversations/' + conversation_id + '/messages',
      headers: { 'api_access_token': token }
    });
    const messages = resp.payload || [];
    const slotNotes = messages.filter(function(m) {
      return m.private && typeof m.content === 'string' && m.content.startsWith('SOFIA_SLOTS:');
    });
    if (slotNotes.length > 0) {
      const lastNote = slotNotes[slotNotes.length - 1];
      const raw = lastNote.content.replace('SOFIA_SLOTS:', '');
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        slots = parsed;
      } else {
        slots = parsed.slots || [];
        original_message = parsed.original_message || '';
        slot_clinic_name = parsed.clinic_name || '';
        slot_clinic_phone = parsed.clinic_phone || '';
      }
      console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_RETRIEVED', count: slots.length, orig: original_message.substring(0,40) }));
    } else {
      console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_NOTE_NOT_FOUND' }));
    }
  } catch(e) {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_FETCH_ERROR', error: e.message }));
  }
}

// Si usuario pide otro dia, limpiar label y reiniciar scheduling
if ($json.day_change_request === true && awaiting) {
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: "https://chat.redsolucionesti.com/api/v1/accounts/" + validar_data.account_id + "/conversations/" + validar_data.conversation_id + "/labels",
      headers: { "api_access_token": $node["Merge Clinic Data"].json.chatwoot_api_token, "Content-Type": "application/json" },
      body: { labels: [] }, json: true
    });
  } catch(e) { /* non-fatal */ }
  return [{ json: { ...$json, slot_confirmation_pending: false, is_second_interaction: false, offered_slots: [], day_change_request: true } }];
}

return [{
  json: {
    ...$json,
    intent: $json.intent,
    confidence: $json.confidence,
    slot_confirmation_pending: awaiting && (
      $json.classified_by === 'SLOT_CONFIRMATION_DETECTOR' ||
      $json.classified_by === 'SLOT_AFFIRMATION_DETECTOR' ||
      $json.classified_by === 'DAY_CHANGE_DETECTOR'
    ),
    offered_slots: slots,
    original_appointment_message: original_message,
    slot_clinic_name: slot_clinic_name,
    slot_clinic_phone: slot_clinic_phone,
    is_second_interaction: awaiting
  }
}];

// ============================================
// PROCESS USER'S SLOT SELECTION
// ============================================
const raw = ($json.message_text || '');
const message = raw.toLowerCase().trim();
const slots = $json.offered_slots || [];

if (slots.length === 0) {
    return [{
        json: {
            ...$json,
            slot_chosen: false,
            needs_clarification: true,
            error_reason: 'NO_SLOTS_IN_CONTEXT'
        }
    }];
}

// Normalize message for matching (handles accents)
const msgNorm = message.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

let chosen_slot = null;
let chosen_index = -1;

// Match by number or ordinal words
if (msgNorm.match(/\b1\b/) || msgNorm.includes('primer') || msgNorm.includes('uno') || msgNorm.includes('primero') || msgNorm.includes('primera')) {
    chosen_slot = slots[0]; chosen_index = 0;
} else if (msgNorm.match(/\b2\b/) || msgNorm.includes('segund') || msgNorm.includes('dos')) {
    chosen_slot = slots[1]; chosen_index = 1;
} else if (msgNorm.match(/\b3\b/) || msgNorm.includes('tercer') || msgNorm.includes('tres')) {
    chosen_slot = slots[2]; chosen_index = 2;
}

// If single affirmative with no number, pick slot 1
if (!chosen_slot) {
    const affirmatives = ["si","sip","yes","ok","dale","claro","listo","va","bueno","perfecto","de acuerdo","adelante","quiero ese","esa","ese"];
    if (affirmatives.includes(msgNorm) || affirmatives.some(function(a) { return msgNorm.startsWith(a + " ") || msgNorm === a; })) {
        chosen_slot = slots[0]; chosen_index = 0;
    }
}

// Try to match by day name
if (!chosen_slot) {
    const days = ['lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado', 'domingo'];
    for (let i = 0; i < slots.length; i++) {
        const slot_text = (slots[i].date || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        for (const day of days) {
            if (msgNorm.includes(day) && slot_text.includes(day)) {
                chosen_slot = slots[i]; chosen_index = i; break;
            }
        }
        if (chosen_slot) break;
    }
}

if (!chosen_slot) {
    return [{
        json: {
            ...$json,
            slot_chosen: false,
            needs_clarification: true,
            error_reason: 'SLOT_NOT_IDENTIFIED'
        }
    }];
}

return [{
    json: {
        ...$json,
        slot_chosen: true,
        chosen_slot: chosen_slot,
        chosen_slot_index: chosen_index + 1,
        needs_clarification: false
    }
}];

