            body: { alert: 'CROSS_VALIDATION_DOWN', clinic_id: clinicId, error: e.message, ts: new Date().toISOString() },
            json: true }).catch(() => {});
        throw new Error(msg);
    }
    if (crossValid !== true) {
        if (ALERT_URL) await this.helpers.httpRequest({ method: 'POST', url: ALERT_URL,
            body: { alert: 'TENANT_ISOLATION_VIOLATION', severity: 'CRITICAL', clinic_id: clinicId, inbox_id: inboxId, ts: new Date().toISOString() },
            json: true }).catch(() => {});
        throw new Error(`SECURITY_ERROR: inbox ${inboxId} no pertenece a clinic ${clinicId}`);
    }
}

// 3. GOVERNANCE CHECK con retry (fail-closed)
let govResult;
try {
    govResult = await supabaseRpc('upsert_conversation', {
        p_clinic_id:                clinicId,
        p_chatwoot_conversation_id: conversationId,
        p_patient_name:             patientName,
        p_last_message:             messageText
    }, { attempts: 3 });
} catch(e) {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'GOVERNANCE_FAILED', error: e.message }));
    if (ALERT_URL) await this.helpers.httpRequest({ method: 'POST', url: ALERT_URL,
        body: { alert: 'BOT_PAUSE_CHECK_DOWN', severity: 'HIGH', clinic_id: clinicId, error: e.message, ts: new Date().toISOString() },
        json: true }).catch(() => {});
    throw new Error('GOVERNANCE_UNAVAILABLE: ' + e.message);
}

const conversation = Array.isArray(govResult) ? govResult[0] : govResult;

if (conversation && conversation.bot_paused === true) {
    console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'BOT_PAUSED_GATE', clinic_id: clinicId, conversation_id: conversationId }));
    return [];
}

return [{ json: {
    ...$json,
    governance_conversation_id: conversation?.conversation_id ?? null,
    governance_status:          conversation?.status ?? 'active',
    governance_checked:         true,
    _start_ts:                  START_TS   // Para calcular duration_ms al final
} }];

// WEBHOOK SECURITY GATE
// Chatwoot signs requests with HMAC-SHA256 and sends x-chatwoot-signature: sha256=<hmac>
// We verify the signature header is present and well-formed.
const item = $input.first();
const headers = item.json.headers || {};

// Chatwoot sends x-chatwoot-signature (not x-chatwoot-webhook-token)
const sig = headers["x-chatwoot-signature"] || headers["X-Chatwoot-Signature"] || "";

if (!sig || !sig.startsWith("sha256=")) {
  console.warn(JSON.stringify({ ts: new Date().toISOString(), event: "WEBHOOK_SIGNATURE_MISSING", sig: sig }));
  return [];
}

return [item];

// ── Retry Library (exponential backoff + jitter) ──────────────────────────
const withRetry = async (fn, opts = {}) => {
    const {
        attempts   = 3,
        baseMs     = 1000,      // 1s base
        maxMs      = 30000,     // 30s max wait
        noRetryOn  = [],        // status codes o strings → no reintentar
        onRetry    = null       // callback(attempt, error)
    } = opts;

    let lastError;
    for (let i = 0; i < attempts; i++) {
        try {
            return await fn();
        } catch(e) {
            lastError = e;
            const isLast = i === attempts - 1;
            // No reintentar si es un error de negocio (400, 409, etc.)
            const skip = noRetryOn.some(code => e.message?.includes(String(code)));
            if (isLast || skip) throw e;

            // Exponential backoff con jitter (evita thundering herd)
            const delay = Math.min(baseMs * Math.pow(2, i) + Math.random() * 1000, maxMs);
            if (onRetry) onRetry(i + 1, e, delay);
            console.warn(JSON.stringify({
                ts: new Date().toISOString(),
                event: 'RETRY',
                attempt: i + 1,
                delay_ms: Math.round(delay),
                error: e.message?.substring(0, 100)
            }));
            await new Promise(r => setTimeout(r, delay));
        }
    }
    throw lastError;
};

// Helper: llamada a Supabase RPC con retry automático
const supabaseRpc = async (rpcName, body, { attempts = 3 } = {}) => {
    const SUPABASE_URL  = $env.N8N_SUPABASE_URL;
    const SERVICE_KEY   = $env.N8N_SUPABASE_SERVICE_KEY;
    if (!SUPABASE_URL || !SERVICE_KEY) throw new Error('CONFIG_ERROR: Supabase env vars no configuradas');

    return withRetry(async () => {
        return this.helpers.httpRequest({
            method: 'POST',
            url: `${SUPABASE_URL}/rest/v1/rpc/${rpcName}`,
            headers: {
                'apikey':        SERVICE_KEY,
                'Authorization': 'Bearer ' + SERVICE_KEY,
                'Content-Type':  'application/json'
            },
            body,
            json: true
        });
    }, {
        attempts,
        baseMs: 500,
        noRetryOn: ['400', '422', '409']  // Errores de validación → no reintentar
    });
};
// ─────────────────────────────────────────────────────────────────────────────

// ====================================================
// REGISTRAR EJECUCIÓN — Logging de resultado
// Último nodo del workflow. Registra en execution_log.
// ====================================================

const clinicId       = $json.clinic_id;
const conversationId = String($json.conversation_id || '');
const intent         = $json.intent || 'UNKNOWN';
const startTs        = $json._start_ts || Date.now();
const durationMs     = Date.now() - startTs;

// Determinar status según datos del flujo
const status = $json.appointment_error
    ? 'error'
    : ($json.governance_checked === false
        ? 'error'
        : 'success');

const logPayload = {
    p_clinic_id:         clinicId,
    p_conversation_id:   conversationId,
    p_workflow_id:       '37SLdWISQLgkHeXk',
    p_intent:            intent,
    p_status:            status,
    p_duration_ms:       durationMs,
    p_openai_tokens:     $json._openai_tokens || null,
    p_openai_latency_ms: $json._openai_latency || null,
    p_inbox_id:          $json.inbox_id || null
};

try {
    await supabaseRpc('log_execution', logPayload, { attempts: 2 });
    console.log(JSON.stringify({
        ts: new Date().toISOString(),
        event: 'EXECUTION_LOGGED',
        status,
        duration_ms: durationMs,
        intent,
        clinic_id: clinicId
    }));
} catch(e) {
    // Logging falla → no bloquear el flujo (best-effort)
    console.warn(JSON.stringify({ ts: new Date().toISOString(), event: 'LOG_EXECUTION_FAILED', error: e.message }));
}

// Limpiar campos internos antes de pasar al siguiente nodo
const output = Object.assign({}, $json);
delete output._start_ts;
delete output._openai_tokens;
delete output._openai_latency;

return [{ json: output }];

const ctx = $input.first().json;
const botConfig = ctx.bot_config || {};
const menu = botConfig.menu || {};
const clinicName = ctx.clinic_name || "la clinica";
const nl = String.fromCharCode(10);

const header = (menu.header || (
  "\u00a1Hola! Soy *SofIA*, tu asistente de *" + clinicName + "* \ud83e\uddb7" + nl +
  "\u00bfEn qu\u00e9 te puedo ayudar hoy?"
)).replace("{clinic_name}", clinicName);

const footer = menu.footer || (nl + nl + "Responde con el *n\u00famero* de tu opci\u00f3n \ud83d\udc47");

const options = menu.options || [
  { id: "1", emoji: "\ud83d\udcc5", label: "Agendar una cita",          intent: "CREATE_EVENT" },
  { id: "2", emoji: "\ud83d\udcb0", label: "Precios y servicios",       intent: "INFO",  query: "precios servicios tratamientos de la clinica" },
  { id: "3", emoji: "\ud83d\udccd", label: "Horarios y ubicaci\u00f3n", intent: "INFO",  query: "horarios de atencion ubicacion direccion como llegar" },
  { id: "4", emoji: "\ud83d\udccb", label: "Ver o cancelar mi cita",    intent: "APPOINTMENT_STATUS" },
  { id: "5", emoji: "\ud83d\udc69\u200d\u2695\ufe0f", label: "Hablar con un asesor", intent: "HUMAN" }
];

const optionLines = options.map(function(o) { const em = o.emoji ? o.emoji + " " : ""; return em + "*" + o.id + ".* " + o.label; }).join(nl);
const menuText = header + nl + nl + optionLines + footer;

// Reset slot confirmation state — clear awaiting_slot label
try {
  await this.helpers.httpRequest({
    method: "POST",
    url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/labels",
    headers: { "api_access_token": $node["Merge Clinic Data"].json.chatwoot_api_token, "Content-Type": "application/json" },
    body: { labels: [] },
    json: true
  });
} catch(e) { /* non-fatal — continue showing menu */ }

return [{ json: Object.assign({}, ctx, { menu_text: menuText, menu_options: options, _last_message_was_menu: true }) }];

const ctx = $input.first().json;
const opcion = String(ctx.menu_selection_option || "").trim();

// Get menu options: from context, bot_config, or hardcoded defaults
let menuOptions = ctx.menu_options || [];

if (!menuOptions.length && ctx.bot_config) {
  let bc = ctx.bot_config;
  // bot_config may arrive as a character-indexed object (stringified JSONB) - reconstruct
  if (typeof bc === 'object' && bc !== null && bc['0'] !== undefined) {
    const keys = Object.keys(bc).sort(function(a, b) { return Number(a) - Number(b); });
    const bcStr = keys.map(function(k) { return bc[k]; }).join('');
    try { bc = JSON.parse(bcStr); } catch(e) { bc = {}; }
  }
  if (typeof bc === 'string') {
    try { bc = JSON.parse(bc); } catch(e) { bc = {}; }
  }
  if (bc && bc.menu && Array.isArray(bc.menu.options)) {
    menuOptions = bc.menu.options;
  }
}

// Hardcoded defaults as ultimate fallback (matches Generar Texto Menu defaults)
if (!menuOptions.length) {
  menuOptions = [
    { id: "1", intent: "CREATE_EVENT" },
    { id: "2", intent: "INFO", query: "precios y servicios tratamientos de la clinica" },
    { id: "3", intent: "INFO", query: "horarios de atencion ubicacion direccion como llegar" },
    { id: "4", intent: "APPOINTMENT_STATUS" },
    { id: "5", intent: "HUMAN" }
  ];
}

const selected = menuOptions.find(function(o) { return String(o.id) === opcion; });
if (!selected || !selected.intent) {
  return [{ json: Object.assign({}, ctx, { intent: "MENU", classified_by: "MENU_INVALID", skip_ai: true }) }];
}

const out = Object.assign({}, ctx, {
  intent: selected.intent,
  classified_by: "MENU_SELECTION_RESOLVED",
  skip_ai: true
});
if (selected.intent === "INFO" && selected.query) {
  out.message_text = selected.query;
}
return [{ json: out }];

const ctx = $input.first().json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const phone     = ctx.contact_phone || "";
const clinicId  = ctx.clinic_id || "";

if (!phone) {
  return [{ json: Object.assign({}, ctx, { raw_appointments: [], has_appointments: false, phone_missing: true }) }];
}

let appointments = [];
const fields = "select=id,start_time,end_time,service,status,patient_name";
const base   = SUPABASE_URL + "/rest/v1/appointments";
const hdrs   = { apikey: SERVICE_KEY, Authorization: "Bearer " + SERVICE_KEY };

// Try contact_phone field first, then phone field
const queries = [
  base + "?contact_phone=eq." + encodeURIComponent(phone) + "&clinic_id=eq." + clinicId + "&status=neq.cancelled&order=start_time.asc&limit=5&" + fields,
  base + "?phone=eq."         + encodeURIComponent(phone) + "&clinic_id=eq." + clinicId + "&status=neq.cancelled&order=start_time.asc&limit=5&" + fields
];

for (var qi = 0; qi < queries.length; qi++) {
  try {
    const res = await this.helpers.httpRequest({ method: "GET", url: queries[qi], headers: hdrs, json: true });
    if (res && res.length > 0) { appointments = res; break; }
  } catch(e) { /* try next */ }
}

return [{ json: Object.assign({}, ctx, { raw_appointments: appointments, has_appointments: appointments.length > 0 }) }];

const ctx = $input.first().json;
const appts = ctx.raw_appointments || [];
const clinicName = ctx.clinic_name || "la clinica";
const message = (ctx.message_text || "").toLowerCase();

const cancelMatch = message.match(/cancelar\s*([1-9])/);
if (cancelMatch) {
  const cancelIdx = parseInt(cancelMatch[1]) - 1;
  const apptToCancel = appts[cancelIdx];
  if (apptToCancel) {
    const dt = new Date(apptToCancel.start_time);
    const fecha = dt.toLocaleDateString("es-PE", { weekday: "long", day: "numeric", month: "long" });
    return [{ json: Object.assign({}, ctx, {
      appointments_text: "Para cancelar tu cita del " + fecha + ", te conecto con un agente que te ayudara.\n\nUn momento por favor.",
      intent: "HUMAN",
      escalation_reason: "CANCEL_APPOINTMENT",
      escalation_message: "Paciente solicita cancelar cita del " + fecha + ".",
      should_escalate: true
    }) }];
  }
}

const STATUS_ES = {
  scheduled: "Agendada",
  confirmed:  "Confirmada",
  completed:  "Completada",
  no_show:    "No se presento",
  cancelled:  "Cancelada"
};

if (!appts || appts.length === 0) {
  var noApptText = "";
  if (ctx.phone_missing) {
    noApptText = "No pude identificar tu numero. Por favor contacta directamente a la clinica.";
  } else {
    noApptText = "No encontre citas activas en " + clinicName + ".\n\n*1.* Agendar nueva cita\n*2.* Hablar con un agente";
  }
  return [{ json: Object.assign({}, ctx, { appointments_text: noApptText }) }];
}

var lines = appts.map(function(a, i) {
  var dt    = new Date(a.start_time);
  var fecha = dt.toLocaleDateString("es-PE", { weekday: "long", day: "numeric", month: "long" });
  var hora  = dt.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit" });
  var serv  = a.service || "Consulta general";
  var est   = STATUS_ES[a.status] || a.status;
  return (i + 1) + ". *" + fecha + "* a las " + hora + "\n   " + serv + " - " + est;
});

var text = "Tus citas en " + clinicName + ":\n\n" + lines.join("\n\n");
text += "\n\n_Para cancelar escribe: *cancelar 1* (o el numero de la cita)_";
text += "\n\n*1.* Agendar otra cita   *2.* Hablar con agente";

return [{ json: Object.assign({}, ctx, { appointments_text: text }) }];

// RESOLVER DOCTOR — busca doctores activos de la clínica y hace match con preferencia del paciente
// Si no hay doctores → fallback a modo clínica (igual que antes)
const ctx = $("Explicar Agendamiento").item.json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const clinic_id    = ctx.clinic_id;

var doctors = [];
try {
  doctors = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/rpc/list_doctors",
    headers: { apikey: SERVICE_KEY, Authorization: "Bearer " + SERVICE_KEY, "Content-Type": "application/json" },
    body: { p_clinic_id: clinic_id },
    json: true
  });
  if (!Array.isArray(doctors)) doctors = [];
} catch(e) {
  console.warn(JSON.stringify({ ts: new Date().toISOString(), event: "DOCTORS_FETCH_ERROR", error: e.message }));
  doctors = [];
}

// Match doctor by name or specialty
var preferred_name = (ctx.preferred_doctor_name || "").toLowerCase().trim();
var preferred_spec = (ctx.preferred_specialty   || "").toLowerCase().trim();
var selected_doctor = null;

if (preferred_name && doctors.length > 0) {
  // Try last name first, then full name
  selected_doctor = doctors.find(function(d) {
    var full = (d.first_name + " " + d.last_name).toLowerCase();
    var last = d.last_name.toLowerCase();
    return last.includes(preferred_name) || preferred_name.includes(last) || full.includes(preferred_name);
  }) || null;
}

if (!selected_doctor && preferred_spec && doctors.length > 0) {
  selected_doctor = doctors.find(function(d) {
    return d.specialty.toLowerCase().includes(preferred_spec);
  }) || null;
}

console.log(JSON.stringify({
  ts: new Date().toISOString(),
  event: "DOCTOR_RESOLVED",
  total_doctors: doctors.length,
  selected: selected_doctor ? selected_doctor.last_name : null,
  mode: selected_doctor ? "specific" : (doctors.length > 0 ? "any" : "legacy")
}));

return [{ json: Object.assign({}, ctx, {
  available_doctors: doctors,
  selected_doctor: selected_doctor,
  doctor_selection_mode: selected_doctor ? "specific" : (doctors.length > 0 ? "any" : "legacy")
}) }];

