// Detecta si el mensaje viene del CTA de la landing page
const message = ($json.message_text || "").toLowerCase().trim();
const isLandingLead =
  message.includes("quiero ver c") ||
  message.includes("como funciona sofia") ||
  message.includes("quiero ver como funciona") ||
  message.includes("hola, quiero ver");

return [{
  json: {
    ...$json,
    is_landing_lead: isLandingLead,
    lead_detected_at: new Date().toISOString()
  }
}];

// Respuesta especial para leads desde landing page
return [{
  json: {
    ...$json,
    lead_captured: true
  }
}];

// ============================================
// VALIDAR INPUT + DETECTAR CONTACTO NUEVO
